mapper.select:
/** CmmtMemberDao.select */
select

from cmmt_member
where
	member_id = #{memberId}

/** CmmtMemberDao.selectList_blackMemberToNormal */ select
from cmmt_member where
member_st = 'BLACK' and black_list_end_day < to_char(now(), 'yyyymmdd')

mapper.update:
/** CmmtMemberDao.update */
update cmmt_member set
	 login_id      			= #{loginId}
	,enc_passwd    			= #{encPasswd}
	,passwd_dt     			= #{passwdDt}
	,passwd_init   			= #{passwdInit}
	,member_nm     			= #{memberNm}
	,nickname      			= #{nickname}
	,gender        			= #{gender}
	,authority_id  			= #{authorityId}
	,member_st    			= #{memberSt}
	,member_st_dt  			= #{memberStDt}
	,black_list_begin_day   = #{blackListBeginDay}
	,black_list_end_day     = #{blackListEndDay}
	,black_list_reason      = #{blackListReason}
	,member_type   			= #{memberType}
	,ci            			= #{ci}
	,enc_email     			= #{encEmail}
	,enc_birthday  			= #{encBirthday}
	,enc_mobile_no 			= #{encMobileNo}
	,bizrno        			= #{bizrno}
	,refresh_token 			= #{refreshToken}
	,kakao_token            = #{kakaoToken}
	,naver_token            = #{naverToken}
	,google_token           = #{googleToken}
	,last_login_dt          = #{lastLoginDt}
	,creator_id    			= #{creatorId}
	,created_dt    			= #{createdDt}
	,updater_id    			= #{updaterId}
	,updated_dt    			= #{updatedDt}
where
	member_id = #{memberId}

mapper.select:
/** CmmtMemberDao.selectList_lastLoginDt */ select
from cmmt_member where
member_st not in ('DORMANT', 'SECESSION') and ( last_login_dt between to_timestamp(#{day} || '000000', 'yyyymmddhh24miss') and to_timestamp(#{day} || '235959', 'yyyymmddhh24miss') or ( last_login_dt is null and created_dt between to_timestamp(#{day} || '000000', 'yyyymmddhh24miss') and to_timestamp(#{day} || '235959', 'yyyymmddhh24miss') ) )

/** CmmtMemberDao.selectList_memberSt */
select

from cmmt_member
where member_st = #{memberSt}

	and date_part('DAY', now() - member_st_dt) > #{day}

mapper.delete:
/** CmmtMemberDao.delete */
delete
from cmmt_member
where member_id = #{memberId}
